def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    pres = Presentation(modified_ppt_path)
    slides = list(pres.slides)
    if len(slides) < 4:
        return ("Not enough slides in presentation.", 0.0)
    slide = slides[3]
    for shape in slide.shapes:
        if shape.has_table:
            table = shape.table
            headers = [cell.text_frame.text.strip().lower() for cell in table.rows[0].cells]
            required = ['researcher', 'year', 'key finding']
            found = [any(req in header for header in headers) for req in required]
            if all(found):
                return ("Table has all required columns.", 1.0)
            else:
                missing = [req for req, f in zip(required, found) if not f]
                return (f"Missing columns: {', '.join(missing)}.", 0.0)
    return ("No table found on the slide.", 0.0)

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    pres_mod = Presentation(modified_ppt_path)
    mod_slides = list(pres_mod.slides)
    if len(mod_slides) < 4:
        return ("Modified presentation does not have enough slides.", 0.0)
    new_slide = mod_slides[3]
    table = None
    for shape in new_slide.shapes:
        if shape.has_table:
            table = shape.table
            break
    if not table:
        return ("No table found on new slide.", 0.0)

    # Each experiment from slide 3 can be identified by EITHER its experiment
    # name OR any associated researcher / study-token. Accept the row if any
    # token for that experiment appears anywhere in the table.
    experiments = [
        ("Social Facilitation",     ["social facilitation", "triplett"]),
        ("Obedience",               ["obedience", "milgram"]),
        ("When Prophecy Fails",     ["when prophecy fails", "festinger", "cognitive dissonance"]),
        ("Illusionary Correlation", ["illusionary correlation", "illusory correlation", "hamilton", "gifford"]),
        ("Attitudes Vs Actions",    ["attitudes vs actions", "attitudes vs. actions", "lapiere", "la piere", "lapi\u00e8re"]),
    ]
    nrows = table.rows.__len__()
    ncols = table.columns.__len__()
    all_text = " | ".join(
        table.cell(r, c).text_frame.text.strip().lower()
        for r in range(nrows) for c in range(ncols)
    )
    num_found = 0
    missing = []
    for name, tokens in experiments:
        if any(tok in all_text for tok in tokens):
            num_found += 1
        else:
            missing.append(name)
    total = len(experiments)
    msg = f"{num_found} out of {total} experiments found in table"
    if missing:
        msg += f" (missing: {', '.join(missing)})"
    return (msg, min(1.0, num_found / total))

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    pres = Presentation(modified_ppt_path)
    slides = list(pres.slides)
    if len(slides) < 4:
        return ("Not enough slides in presentation.", 0.0)
    slide = slides[3]
    table = None
    for shape in slide.shapes:
        if shape.has_table:
            table = shape.table
            break
    if not table:
        return ("No table found on new slide.", 0.0)
    nrows = table.rows.__len__()
    ncols = table.columns.__len__()
    if nrows <= 1:
        return ("Table has no data rows.", 0.0)
    empty_cells = 0
    total_cells = (nrows-1)*ncols
    for i in range(1, nrows):
        for j in range(ncols):
            text = table.cell(i, j).text_frame.text.strip()
            if not text:
                empty_cells += 1
    if total_cells == 0:
        return ("No data cells.", 0.0)
    frac_filled = 1.0 - (empty_cells / total_cells)
    if frac_filled < 1.0:
        return (f"{empty_cells} empty cells out of {total_cells}.", frac_filled)
    return ("All data cells are filled.", 1.0)

